/**
 * @name XSS via JSP tag output without escaping
 * @description User-controlled input written to JspWriter without HTML encoding
 * @kind path-problem
 * @problem.severity error
 * @id java/xss-jsp-writer
 * @tags security
 *       external/cwe/cwe-079
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module JSPWriterXSSConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // JspWriter
    exists(MethodCall mc |
      (mc.getMethod().hasName("print") or mc.getMethod().hasName("println") or mc.getMethod().hasName("write")) and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("javax.servlet.jsp", "JspWriter") and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // pageContext.getOut().write(...)
    exists(MethodCall mc |
      (mc.getMethod().hasName("print") or mc.getMethod().hasName("println") or mc.getMethod().hasName("write")) and
      mc.getQualifier().(MethodCall).getMethod().hasName("getOut") and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // Custom tag doTag/doStartTag output
    exists(MethodCall mc |
      mc.getMethod().hasName("print") and
      mc.getQualifier().(MethodCall).getMethod().hasName("getJspContext") and
      sink.asExpr() = mc.getArgument(0)
    )
  }
}

module JSPWriterXSSFlow = TaintTracking::Global<JSPWriterXSSConfig>;
import JSPWriterXSSFlow::PathGraph

from JSPWriterXSSFlow::PathNode source, JSPWriterXSSFlow::PathNode sink
where JSPWriterXSSFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Potential XSS via JSP writer output with user input from $@.", source.getNode(), "user input"

/**
 * @name XSS in custom JSP tag writers - direct user input to HTML output
 * @description Custom JSP tags writing user-controlled data to HTML output without encoding
 * @kind path-problem
 * @problem.severity error
 * @id java/xss-jsptag-writer
 * @tags security
 *       external/cwe/cwe-079
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module JSPTagWriterConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // PageContext.getOut().print/println/write
    exists(MethodCall mc |
      (mc.getMethod().hasName("print") or mc.getMethod().hasName("println") or mc.getMethod().hasName("write")) and
      sink.asExpr() = mc.getArgument(0) and
      mc.getEnclosingCallable().getDeclaringType().getASupertype*().hasQualifiedName("javax.servlet.jsp.tagext", "TagSupport")
    )
    or
    // StringBuffer/StringBuilder append used to build HTML in tag handlers
    exists(MethodCall mc |
      mc.getMethod().hasName("append") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.lang", "AbstractStringBuilder") and
      sink.asExpr() = mc.getArgument(0) and
      mc.getEnclosingCallable().getDeclaringType().getASupertype*().hasQualifiedName("javax.servlet.jsp.tagext", "TagSupport")
    )
  }
}

module JSPTagWriterFlow = TaintTracking::Global<JSPTagWriterConfig>;
import JSPTagWriterFlow::PathGraph

from JSPTagWriterFlow::PathNode source, JSPTagWriterFlow::PathNode sink
where JSPTagWriterFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Potential XSS in JSP tag handler: user input from $@ flows to HTML output.", source.getNode(), "user input"

/**
 * @name XSS via error messages including request data
 * @description Exception messages or error pages that include request parameters without encoding
 * @kind path-problem
 * @problem.severity error
 * @id java/xss-error-pages
 * @tags security
 *       external/cwe/cwe-079
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module ErrorXSSConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // setAttribute on request/session - used to pass error messages to JSP pages
    exists(MethodCall mc |
      mc.getMethod().hasName("setAttribute") and
      (
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("javax.servlet", "ServletRequest") or
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("javax.servlet.http", "HttpSession")
      ) and
      sink.asExpr() = mc.getArgument(1)
    )
  }
}

module ErrorXSSFlow = TaintTracking::Global<ErrorXSSConfig>;
import ErrorXSSFlow::PathGraph

from ErrorXSSFlow::PathNode source, ErrorXSSFlow::PathNode sink
where ErrorXSSFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "User input from $@ stored in request/session attribute - may be displayed in HTML without encoding.", source.getNode(), "user input"

/**
 * @name XSS in XMLUI ChoiceLookupTransformer and AbstractSearch via request parameters
 * @description User parameters in XMLUI components reflected without encoding
 * @kind path-problem
 * @problem.severity error
 * @id java/xss-xmlui-search-choice
 * @tags security
 *       external/cwe/cwe-079
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module XmlUIXSSConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // Wing element addContent/setValue - adds text content to XML/HTML output
    exists(MethodCall mc |
      (
        mc.getMethod().hasName("addContent") or
        mc.getMethod().hasName("setValue") or
        mc.getMethod().hasName("setRaw") or
        mc.getMethod().hasName("addPara")
      ) and
      mc.getMethod().getDeclaringType().getQualifiedName().matches("org.dspace.app.xmlui%") and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // Print to response from XMLUI
    exists(MethodCall mc |
      (mc.getMethod().hasName("print") or mc.getMethod().hasName("println") or mc.getMethod().hasName("write")) and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.io", "Writer") and
      sink.asExpr() = mc.getArgument(0) and
      mc.getEnclosingCallable().getDeclaringType().getQualifiedName().matches("org.dspace.app.xmlui%")
    )
  }
}

module XmlUIXSSFlow = TaintTracking::Global<XmlUIXSSConfig>;
import XmlUIXSSFlow::PathGraph

from XmlUIXSSFlow::PathNode source, XmlUIXSSFlow::PathNode sink
where XmlUIXSSFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Potential XSS in XMLUI component: user input from $@ flows to output.", source.getNode(), "user input"
